onClick:
{{
  mark_self_collected_api.run()
    .then(() => {
      showAlert('Warehouse collection recorded successfully', 'success');

      // Clear widgets for next use
      resetWidget("inpCollectorName", true);
      resetWidget("inpCollectorPhone", true);
      resetWidget("selIDType", true);
      resetWidget("inpIDNumber", true);
      resetWidget("inpDocName", true);
      resetWidget("inpCollectionNotes", true);

      closeModal('mdlCollectionDetails');
      closeModal('mdlSelectInvoice');
      getPendingInvoices.run(); // Refresh the list
    })
    .catch((err) => {
      showAlert('Error: ' + mark_self_collected_api.data.error, 'error');
    });
}}
